# Python 3.11+
"""The ride-selection SEAM (Strategy).

The rider expresses a PREFERENCE for which matching ride to take; that preference
is exactly the policy the product will keep adding to. Each strategy receives the
already-filtered candidate rides (right route, enough seats) and picks one — or
None if none fit the preference.
"""

from abc import ABC, abstractmethod

from models import Ride


class RideSelectionStrategy(ABC):
    @abstractmethod
    def select(self, rides: list[Ride]) -> Ride | None:
        """Pick the best ride for this preference, or None."""


class EarliestEndingStrategy(RideSelectionStrategy):
    """Get the rider to their destination soonest: minimise end_time (start+duration)."""

    def select(self, rides: list[Ride]) -> Ride | None:
        if not rides:
            return None
        return min(rides, key=lambda r: (r.end_time, r.id))   # tie-break by id for determinism


class MostVacantStrategy(RideSelectionStrategy):
    """Prefer the emptiest ride — most elbow room / most likely to still have space."""

    def select(self, rides: list[Ride]) -> Ride | None:
        if not rides:
            return None
        return max(rides, key=lambda r: (r.available_seats, -r.start_time, r.id))


class PreferredVehicleStrategy(RideSelectionStrategy):
    """Only consider rides on the rider's preferred vehicle model; among those, earliest ending."""

    def __init__(self, model: str) -> None:
        self.model = model

    def select(self, rides: list[Ride]) -> Ride | None:
        matching = [r for r in rides if r.vehicle.model == self.model]
        return EarliestEndingStrategy().select(matching)      # reuse: earliest among preferred

