import json, re, glob
def info(f):
    d=json.load(open(f))
    if not isinstance(d,dict): return None
    md=""
    for m in d.get("messages",[]):
        if isinstance(m,dict) and m.get("role")=="assistant":
            for b in (m.get("content") or []):
                if isinstance(b,dict) and b.get("type")=="text": md+=b.get("text","")
    return d.get("title",""), md

# Modern sessions = have §9 Concurrency, dedup by a normalized topic key
KEYS = {
 "ride sharing":"Ride Sharing","vending":"Vending Machine","message broker":"Message Broker (Pub-Sub)",
 "splitwise":"Splitwise","parking":"Parking Lot","notification router":"Notification Router",
 "leaderboard":"Leaderboard","task scheduler":"Task Scheduler","rate limiter":"API Rate Limiter",
 "meeting room":"Meeting Room Reservation","movie ticket":"Movie Ticket Booking","elevator":"Elevator System",
 "coupon":"Coupon Management","ttl":"TTL Key-Value Store","time-to-live":"TTL Key-Value Store",
}
modern=set(); legacy=set()
for f in sorted(glob.glob("data/conversations/*_lld.json")):
    r=info(f)
    if not r: continue
    title,md=r
    tl=title.lower()
    topic=None
    for k,v in KEYS.items():
        if k in tl: topic=v;break
    if topic is None:
        topic=" ".join(title.split())[:32]
    if "Concurrency" in md and ("§9" in md or "## 9" in md or "9. Concurrency" in md):
        modern.add(topic)
    else:
        legacy.add(topic)

print("MODERN (full §1-§9):")
for t in sorted(modern): print("  -",t)
print("\nLEGACY-only topics (older format, no §9):")
for t in sorted(legacy-modern): print("  -",t)
