  },
  {
    key: 'empirical-output',
    prompt: `You are a critical reviewer checking whether a prompt actually PRODUCES good output. Read the HLD prompt at ${PROMPT} (skim for structure), then read the FULL markdown answer inside two freshly-generated sessions it produced: extract transcript[1].blocks[0].md from ${SAMPLE1} (Flash Sale) and ${SAMPLE2} (Web Crawler) using python/json. Judge EMPIRICALLY: does the §1-then-§2 ordering read naturally in the actual output, or is it awkward (e.g. requirements stated, THEN questions that should have preceded them)? Are the clarifying questions in §2 actually scoping questions that logically belong before §1's requirements? Are there repetitive/bloated sections, weak deep dives, or hand-waved capacity numbers in practice? For orderingVerdict, base it on what you actually observe in these two outputs. List concrete, evidence-backed problems (quote the output).`,
  },
]

const critiques = await parallel(LENSES.map(L => () =>
  agent(L.prompt, { label: `critic:${L.key}`, phase: 'Critique', schema: FINDING_SCHEMA, agentType: 'general-purpose' })
))

phase('Synthesize')

const valid = critiques.filter(Boolean)
const synthesis = await agent(
  `You are synthesizing 4 independent expert critiques of an HLD (high-level system design) interview prompt into ONE actionable recommendation set for the prompt's owner.

Here are the 4 critiques (each has a lens, an orderingVerdict on "clarifying-questions-before-requirements?", and a findings list):
